101	/// Internal queue data shared between the worker and stealers.
102	///
103	/// The implementation is based on the following work:
104	///
105	/// 1. [Chase and Lev. Dynamic circular work-stealing deque. SPAA 2005.][chase-lev]
106	/// 2. [Le, Pop, Cohen, and Nardelli. Correct and efficient work-stealing for weak memory models.
107	///    PPoPP 2013.][weak-mem]
108	/// 3. [Norris and Demsky. CDSchecker: checking concurrent data structures written with C/C++
109	///    atomics. OOPSLA 2013.][checker]
110	///
111	/// [chase-lev]: https://dl.acm.org/citation.cfm?id=1073974
112	/// [weak-mem]: https://dl.acm.org/citation.cfm?id=2442524
113	/// [checker]: https://dl.acm.org/citation.cfm?id=2509514
114	struct Inner<T> {
115	    /// The front index.
116	    front: AtomicIsize,
117	
118	    /// The back index.
119	    back: AtomicIsize,
120	
121	    /// The underlying buffer.
122	    buffer: CachePadded<Atomic<Buffer<T>>>,
123	}
124	
125	impl<T> Drop for Inner<T> {
126	    fn drop(&mut self) {
127	        // Load the back index, front index, and buffer.
128	        let b = *self.back.get_mut();
129	        let f = *self.front.get_mut();
130	
131	        unsafe {
132	            let buffer = self.buffer.load(Ordering::Relaxed, epoch::unprotected());
133	
134	            // Go through the buffer from front to back and drop all tasks in the queue.
135	            let mut i = f;
136	            while i != b {
137	                buffer.deref().at(i).drop_in_place();
138	                i = i.wrapping_add(1);
139	            }
140	
141	            // Free the memory allocated by the buffer.
142	            buffer.into_owned().into_box().dealloc();
143	        }
144	    }
145	}
146	
147	/// Worker queue flavor: FIFO or LIFO.
148	#[derive(Clone, Copy, Debug, Eq, PartialEq)]
149	enum Flavor {
150	    /// The first-in first-out flavor.
151	    Fifo,
152	
153	    /// The last-in first-out flavor.
154	    Lifo,
155	}
156	
157	/// A worker queue.
158	///
159	/// This is a FIFO or LIFO queue that is owned by a single thread, but other threads may steal
160	/// tasks from it. Task schedulers typically create a single worker queue per thread.
161	///
162	/// # Examples
163	///
164	/// A FIFO worker:
165	///
166	/// ```
167	/// use crossbeam_deque::{Steal, Worker};
168	///
169	/// let w = Worker::new_fifo();
170	/// let s = w.stealer();
171	///
172	/// w.push(1);
173	/// w.push(2);
174	/// w.push(3);
175	///
176	/// assert_eq!(s.steal(), Steal::Success(1));
177	/// assert_eq!(w.pop(), Some(2));
178	/// assert_eq!(w.pop(), Some(3));
179	/// ```
180	///
181	/// A LIFO worker:
182	///
183	/// ```
184	/// use crossbeam_deque::{Steal, Worker};
185	///
186	/// let w = Worker::new_lifo();
187	/// let s = w.stealer();
188	///
189	/// w.push(1);
190	/// w.push(2);
191	/// w.push(3);
192	///
193	/// assert_eq!(s.steal(), Steal::Success(1));
194	/// assert_eq!(w.pop(), Some(3));
195	/// assert_eq!(w.pop(), Some(2));
196	/// ```
197	pub struct Worker<T> {
198	    /// A reference to the inner representation of the queue.
199	    inner: Arc<CachePadded<Inner<T>>>,
200	
201	    /// A copy of `inner.buffer` for quick access.
202	    buffer: Cell<Buffer<T>>,
203	
204	    /// The flavor of the queue.
205	    flavor: Flavor,
206	
207	    /// Indicates that the worker cannot be shared among threads.
208	    _marker: PhantomData<*mut ()>, // !Send + !Sync
209	}
210	
211	unsafe impl<T: Send> Send for Worker<T> {}
212	
213	impl<T> Worker<T> {
214	    /// Creates a FIFO worker queue.
215	    ///
216	    /// Tasks are pushed and popped from opposite ends.
217	    ///
218	    /// # Examples
219	    ///
220	    /// ```
221	    /// use crossbeam_deque::Worker;
222	    ///
223	    /// let w = Worker::<i32>::new_fifo();
224	    /// ```
225	    pub fn new_fifo() -> Self {
226	        let buffer = Buffer::alloc(MIN_CAP);
227	
228	        let inner = Arc::new(CachePadded::new(Inner {
229	            front: AtomicIsize::new(0),
230	            back: AtomicIsize::new(0),
231	            buffer: CachePadded::new(Atomic::new(buffer)),
232	        }));
233	
234	        Self {
235	            inner,
236	            buffer: Cell::new(buffer),
237	            flavor: Flavor::Fifo,
238	            _marker: PhantomData,
239	        }
240	    }
241	
242	    /// Creates a LIFO worker queue.
243	    ///
244	    /// Tasks are pushed and popped from the same end.
245	    ///
246	    /// # Examples
247	    ///
248	    /// ```
249	    /// use crossbeam_deque::Worker;
250	    ///
251	    /// let w = Worker::<i32>::new_lifo();
252	    /// ```
253	    pub fn new_lifo() -> Self {
254	        let buffer = Buffer::alloc(MIN_CAP);
255	
256	        let inner = Arc::new(CachePadded::new(Inner {
257	            front: AtomicIsize::new(0),
258	            back: AtomicIsize::new(0),
259	            buffer: CachePadded::new(Atomic::new(buffer)),
260	        }));
261	
262	        Self {
263	            inner,
264	            buffer: Cell::new(buffer),
265	            flavor: Flavor::Lifo,
266	            _marker: PhantomData,
267	        }
268	    }
269	
270	    /// Creates a stealer for this queue.
271	    ///
272	    /// The returned stealer can be shared among threads and cloned.
273	    ///
274	    /// # Examples
275	    ///
276	    /// ```
277	    /// use crossbeam_deque::Worker;
278	    ///
279	    /// let w = Worker::<i32>::new_lifo();
280	    /// let s = w.stealer();
281	    /// ```
282	    pub fn stealer(&self) -> Stealer<T> {
283	        Stealer {
284	            inner: self.inner.clone(),
285	            flavor: self.flavor,
286	        }
287	    }
288	
289	    /// Resizes the internal buffer to the new capacity of `new_cap`.
290	    #[cold]
291	    unsafe fn resize(&self, new_cap: usize) {
292	        // Load the back index, front index, and buffer.
293	        let b = self.inner.back.load(Ordering::Relaxed);
294	        let f = self.inner.front.load(Ordering::Relaxed);
295	        let buffer = self.buffer.get();
296	
297	        // Allocate a new buffer and copy data from the old buffer to the new one.
298	        let new = Buffer::alloc(new_cap);
299	        let mut i = f;
300	        while i != b {
301	            unsafe { ptr::copy_nonoverlapping(buffer.at(i), new.at(i), 1) }
302	            i = i.wrapping_add(1);
303	        }
304	
305	        let guard = &epoch::pin();
306	
307	        // Replace the old buffer with the new one.
308	        self.buffer.replace(new);
309	        let old =
310	            self.inner
311	                .buffer
312	                .swap(Owned::new(new).into_shared(guard), Ordering::Release, guard);
313	
314	        // Destroy the old buffer later.
315	        unsafe { guard.defer_unchecked(move || old.into_owned().into_box().dealloc()) }
316	
317	        // If the buffer is very large, then flush the thread-local garbage in order to deallocate
318	        // it as soon as possible.
319	        if mem::size_of::<T>() * new_cap >= FLUSH_THRESHOLD_BYTES {
320	            guard.flush();
321	        }
322	    }
323	
324	    /// Reserves enough capacity so that `reserve_cap` tasks can be pushed without growing the
325	    /// buffer.
326	    fn reserve(&self, reserve_cap: usize) {
327	        if reserve_cap > 0 {
328	            // Compute the current length.
329	            let b = self.inner.back.load(Ordering::Relaxed);
330	            let f = self.inner.front.load(Ordering::SeqCst);
331	            let len = b.wrapping_sub(f) as usize;
332	
333	            // The current capacity.
334	            let cap = self.buffer.get().cap;
335	
336	            // Is there enough capacity to push `reserve_cap` tasks?
337	            if cap - len < reserve_cap {
338	                // Keep doubling the capacity as much as is needed.
339	                let mut new_cap = cap * 2;
340	                while new_cap - len < reserve_cap {
341	                    new_cap *= 2;
342	                }
343	
344	                // Resize the buffer.
345	                unsafe {
346	                    self.resize(new_cap);
347	                }
348	            }
349	        }
350	    }
351	
352	    /// Returns `true` if the queue is empty.
353	    ///
354	    /// ```
355	    /// use crossbeam_deque::Worker;
356	    ///
357	    /// let w = Worker::new_lifo();
358	    ///
359	    /// assert!(w.is_empty());
360	    /// w.push(1);
361	    /// assert!(!w.is_empty());
362	    /// ```
363	    pub fn is_empty(&self) -> bool {
364	        let b = self.inner.back.load(Ordering::Relaxed);
365	        let f = self.inner.front.load(Ordering::SeqCst);
366	        b.wrapping_sub(f) <= 0
367	    }
368	
369	    /// Returns the number of tasks in the deque.
370	    ///
371	    /// ```
372	    /// use crossbeam_deque::Worker;
373	    ///
374	    /// let w = Worker::new_lifo();
375	    ///
376	    /// assert_eq!(w.len(), 0);
377	    /// w.push(1);
378	    /// assert_eq!(w.len(), 1);
379	    /// w.push(1);
380	    /// assert_eq!(w.len(), 2);
381	    /// ```
382	    pub fn len(&self) -> usize {
383	        let b = self.inner.back.load(Ordering::Relaxed);
384	        let f = self.inner.front.load(Ordering::SeqCst);
385	        b.wrapping_sub(f).max(0) as usize
386	    }
387	
388	    /// Pushes a task into the queue.
389	    ///
390	    /// # Examples
391	    ///
392	    /// ```
393	    /// use crossbeam_deque::Worker;
394	    ///
395	    /// let w = Worker::new_lifo();
396	    /// w.push(1);
397	    /// w.push(2);
398	    /// ```
399	    pub fn push(&self, task: T) {
400	        // Load the back index, front index, and buffer.
401	        let b = self.inner.back.load(Ordering::Relaxed);
402	        let f = self.inner.front.load(Ordering::Acquire);
403	        let mut buffer = self.buffer.get();
404	
405	        // Calculate the length of the queue.
406	        let len = b.wrapping_sub(f);
407	
408	        // Is the queue full?
409	        if len >= buffer.cap as isize {
410	            // Yes. Grow the underlying buffer.
411	            unsafe {
412	                self.resize(2 * buffer.cap);
413	            }
414	            buffer = self.buffer.get();
415	        }
416	
417	        // Write `task` into the slot.
418	        unsafe {
419	            buffer.write(b, MaybeUninit::new(task));
420	        }
421	
422	        // ThreadSanitizer does not understand fences, so we omit fence and do store with Release ordering.
423	        #[cfg(not(crossbeam_sanitize_thread))]
424	        atomic::fence(Ordering::Release);
425	        let store_order = if cfg!(crossbeam_sanitize_thread) {
426	            Ordering::Release
427	        } else {
428	            Ordering::Relaxed
429	        };
430	
431	        // Increment the back index.
432	        self.inner.back.store(b.wrapping_add(1), store_order);
433	    }
434	
435	    /// Pops a task from the queue.
436	    ///
437	    /// # Examples
438	    ///
439	    /// ```
440	    /// use crossbeam_deque::Worker;
441	    ///
442	    /// let w = Worker::new_fifo();
443	    /// w.push(1);
444	    /// w.push(2);
445	    ///
446	    /// assert_eq!(w.pop(), Some(1));
447	    /// assert_eq!(w.pop(), Some(2));
448	    /// assert_eq!(w.pop(), None);
449	    /// ```
450	    pub fn pop(&self) -> Option<T> {
451	        // Load the back and front index.
452	        let b = self.inner.back.load(Ordering::Relaxed);
453	        let f = self.inner.front.load(Ordering::Relaxed);
454	
455	        // Calculate the length of the queue.
456	        let len = b.wrapping_sub(f);
457	
458	        // Is the queue empty?
459	        if len <= 0 {
460	            return None;
461	        }
462	
463	        match self.flavor {
464	            // Pop from the front of the queue.
465	            Flavor::Fifo => {
466	                // Try incrementing the front index to pop the task.
467	                let f = self.inner.front.fetch_add(1, Ordering::SeqCst);
468	                let new_f = f.wrapping_add(1);
469	
470	                if b.wrapping_sub(new_f) < 0 {
471	                    self.inner.front.store(f, Ordering::Relaxed);
472	                    return None;
473	                }
474	
475	                unsafe {
476	                    // Read the popped task.
477	                    let buffer = self.buffer.get();
478	                    let task = buffer.read(f).assume_init();
479	
480	                    // Shrink the buffer if `len - 1` is less than one fourth of the capacity.
481	                    if buffer.cap > MIN_CAP && len <= buffer.cap as isize / 4 {
482	                        self.resize(buffer.cap / 2);
483	                    }
484	
485	                    Some(task)
486	                }
487	            }
488	
489	            // Pop from the back of the queue.
490	            Flavor::Lifo => {
491	                // Decrement the back index.
492	                let b = b.wrapping_sub(1);
493	                self.inner.back.store(b, Ordering::Relaxed);
494	
495	                atomic::fence(Ordering::SeqCst);
496	
497	                // Load the front index.
498	                let f = self.inner.front.load(Ordering::Relaxed);
499	
500	                // Compute the length after the back index was decremented.
501	                let len = b.wrapping_sub(f);
502	
503	                if len < 0 {
504	                    // The queue is empty. Restore the back index to the original task.
505	                    self.inner.back.store(b.wrapping_add(1), Ordering::Relaxed);
506	                    None
507	                } else {
508	                    // Read the task to be popped.
509	                    let buffer = self.buffer.get();
510	                    let mut task = unsafe { Some(buffer.read(b)) };
511	
512	                    // Are we popping the last task from the queue?
513	                    if len == 0 {
514	                        // Try incrementing the front index.
515	                        if self
516	                            .inner
517	                            .front
518	                            .compare_exchange(
519	                                f,
520	                                f.wrapping_add(1),
521	                                Ordering::SeqCst,
522	                                Ordering::Relaxed,
523	                            )
524	                            .is_err()
525	                        {
526	                            // Failed. We didn't pop anything. Reset to `None`.
527	                            task.take();
528	                        }
529	
530	                        // Restore the back index to the original task.
531	                        self.inner.back.store(b.wrapping_add(1), Ordering::Relaxed);
532	                    } else {
533	                        // Shrink the buffer if `len` is less than one fourth of the capacity.
534	                        if buffer.cap > MIN_CAP && len < buffer.cap as isize / 4 {
535	                            unsafe {
536	                                self.resize(buffer.cap / 2);
537	                            }
538	                        }
539	                    }
540	
541	                    task.map(|t| unsafe { t.assume_init() })
542	                }
543	            }
544	        }
545	    }
546	}
