626	    /// Steals a task from the queue.
627	    ///
628	    /// # Examples
629	    ///
630	    /// ```
631	    /// use crossbeam_deque::{Steal, Worker};
632	    ///
633	    /// let w = Worker::new_lifo();
634	    /// w.push(1);
635	    /// w.push(2);
636	    ///
637	    /// let s = w.stealer();
638	    /// assert_eq!(s.steal(), Steal::Success(1));
639	    /// assert_eq!(s.steal(), Steal::Success(2));
640	    /// ```
641	    pub fn steal(&self) -> Steal<T> {
642	        // Load the front index.
643	        let f = self.inner.front.load(Ordering::Acquire);
644	
645	        // A SeqCst fence is needed here.
646	        //
647	        // If the current thread is already pinned (reentrantly), we must manually issue the
648	        // fence. Otherwise, the following pinning will issue the fence anyway, so we don't
649	        // have to.
650	        if epoch::is_pinned() {
651	            atomic::fence(Ordering::SeqCst);
652	        }
653	
654	        let guard = &epoch::pin();
655	
656	        // Load the back index.
657	        let b = self.inner.back.load(Ordering::Acquire);
658	
659	        // Is the queue empty?
660	        if b.wrapping_sub(f) <= 0 {
661	            return Steal::Empty;
662	        }
663	
664	        // Load the buffer and read the task at the front.
665	        let buffer = self.inner.buffer.load(Ordering::Acquire, guard);
666	        let task = unsafe { buffer.deref().read(f) };
667	
668	        // Try incrementing the front index to steal the task.
669	        // If the buffer has been swapped or the increment fails, we retry.
670	        if self.inner.buffer.load(Ordering::Acquire, guard) != buffer
671	            || self
672	                .inner
673	                .front
674	                .compare_exchange(f, f.wrapping_add(1), Ordering::SeqCst, Ordering::Relaxed)
675	                .is_err()
676	        {
677	            // We didn't steal this task, forget it.
678	            return Steal::Retry;
679	        }
680	
681	        // Return the stolen task.
682	        Steal::Success(unsafe { task.assume_init() })
683	    }
