1232	/// A block in a linked list.
1233	///
1234	/// Each block in the list can hold up to `BLOCK_CAP` values.
1235	struct Block<T> {
1236	    /// The next block in the linked list.
1237	    next: AtomicPtr<Block<T>>,
1238	
1239	    /// Slots for values.
1240	    slots: [Slot<T>; BLOCK_CAP],
1241	}
1242	
1243	impl<T> Block<T> {
1244	    const LAYOUT: Layout = {
1245	        let layout = Layout::new::<Self>();
1246	        assert!(
1247	            layout.size() != 0,
1248	            "Block should never be zero-sized, as it has an AtomicPtr field"
1249	        );
1250	        layout
1251	    };
1252	
1253	    /// Creates an empty block.
1254	    fn new() -> Box<Self> {
1255	        // unsafe { Box::new_zeroed().assume_init() } requires Rust 1.92
1256	        match Global.allocate_zeroed(Self::LAYOUT) {
1257	            Some(ptr) => {
1258	                // SAFETY: This is safe because:
1259	                //  [1] `Block::next` (AtomicPtr) may be safely zero initialized.
1260	                //  [2] `Block::slots` (Array) may be safely zero initialized because of [3, 4].
1261	                //  [3] `Slot::task` (UnsafeCell) may be safely zero initialized because it
1262	                //       holds a MaybeUninit.
1263	                //  [4] `Slot::state` (AtomicUsize) may be safely zero initialized.
1264	                unsafe { Box::from_raw(ptr.as_ptr().cast()) }
1265	            }
1266	            // Handle allocation failure
1267	            None => handle_alloc_error(Self::LAYOUT),
1268	        }
1269	    }
1270	
1271	    /// Waits until the next pointer is set.
1272	    fn wait_next(&self) -> *mut Self {
1273	        let backoff = Backoff::new();
1274	        loop {
1275	            let next = self.next.load(Ordering::Acquire);
1276	            if !next.is_null() {
1277	                return next;
1278	            }
1279	            backoff.snooze();
1280	        }
1281	    }
1282	
1283	    /// Sets the `DESTROY` bit in slots starting from `start` and destroys the block.
1284	    unsafe fn destroy(this: *mut Self, count: usize) {
1285	        // It is not necessary to set the `DESTROY` bit in the last slot because that slot has
1286	        // begun destruction of the block.
1287	        for i in (0..count).rev() {
1288	            let slot = unsafe { (*this).slots.get_unchecked(i) };
1289	
1290	            // Mark the `DESTROY` bit if a thread is still using the slot.
1291	            if slot.state.load(Ordering::Acquire) & READ == 0
1292	                && slot.state.fetch_or(DESTROY, Ordering::AcqRel) & READ == 0
1293	            {
1294	                // If a thread is still using the slot, it will continue destruction of the block.
1295	                return;
1296	            }
1297	        }
1298	
1299	        // No thread is using the block, now it is safe to destroy it.
1300	        drop(unsafe { Box::from_raw(this) });
1301	    }
1302	}
