1364	    /// Creates a new injector queue.
1365	    ///
1366	    /// # Examples
1367	    ///
1368	    /// ```
1369	    /// use crossbeam_deque::Injector;
1370	    ///
1371	    /// let q = Injector::<i32>::new();
