1761	    ///
1762	    /// let w = Worker::new_fifo();
1763	    /// assert_eq!(q.steal_batch_and_pop(&w), Steal::Success(1));
1764	    /// assert_eq!(w.pop(), Some(2));
1765	    /// ```
1766	    pub fn steal_batch_and_pop(&self, dest: &Worker<T>) -> Steal<T> {
1767	        // TODO: we use `MAX_BATCH + 1` as the hard limit for Injecter as the performance is slightly
1768	        // better, but we may change it in the future to be compatible with the same method in Stealer.
1769	        self.steal_batch_with_limit_and_pop(dest, MAX_BATCH + 1)
1770	    }
1771	
1772	    /// Steals no more than `limit` of tasks, pushes them into a worker, and pops a task from that worker.
1773	    ///
1774	    /// How many tasks exactly will be stolen is not specified. That said, this method will try to
1775	    /// steal around half of the tasks in the queue, but also not more than the given limit.
1776	    ///
1777	    /// # Examples
1778	    ///
1779	    /// ```
1780	    /// # if option_env!("MIRI_FALLIBLE_WEAK_CAS").is_some() { return; } // see ci/miri.sh
1781	    /// use crossbeam_deque::{Injector, Steal, Worker};
1782	    ///
1783	    /// let q = Injector::new();
1784	    /// q.push(1);
1785	    /// q.push(2);
1786	    /// q.push(3);
1787	    /// q.push(4);
1788	    /// q.push(5);
1789	    /// q.push(6);
1790	    ///
1791	    /// let w = Worker::new_fifo();
1792	    /// assert_eq!(q.steal_batch_with_limit_and_pop(&w, 2), Steal::Success(1));
1793	    /// assert_eq!(w.pop(), Some(2));
1794	    /// assert_eq!(w.pop(), None);
1795	    ///
1796	    /// q.push(7);
1797	    /// // Setting a large limit does not guarantee that all elements will be popped. In this case,
1798	    /// // half of the elements are currently popped, but the number of popped elements is considered
1799	    /// // an implementation detail that may be changed in the future.
1800	    /// assert_eq!(q.steal_batch_with_limit_and_pop(&w, usize::MAX), Steal::Success(3));
1801	    /// assert_eq!(w.pop(), Some(4));
1802	    /// assert_eq!(w.pop(), Some(5));
1803	    /// assert_eq!(w.pop(), None);
1804	    /// ```
1805	    pub fn steal_batch_with_limit_and_pop(&self, dest: &Worker<T>, limit: usize) -> Steal<T> {
1806	        assert!(limit > 0);
1807	        let mut head;
1808	        let mut block;
1809	        let mut offset;
1810	
1811	        let backoff = Backoff::new();
1812	        loop {
1813	            head = self.head.index.load(Ordering::Acquire);
1814	            block = self.head.block.load(Ordering::Acquire);
1815	
1816	            // Calculate the offset of the index into the block.
1817	            offset = (head >> SHIFT) % LAP;
1818	
1819	            // If we reached the end of the block, wait until the next one is installed.
1820	            if offset == BLOCK_CAP {
1821	                backoff.snooze();
1822	            } else {
1823	                break;
1824	            }
1825	        }
1826	
1827	        let mut new_head = head;
1828	        let advance;
1829	
1830	        if new_head & HAS_NEXT == 0 {
1831	            atomic::fence(Ordering::SeqCst);
1832	            let tail = self.tail.index.load(Ordering::Relaxed);
1833	
1834	            // If the tail equals the head, that means the queue is empty.
1835	            if head >> SHIFT == tail >> SHIFT {
1836	                return Steal::Empty;
1837	            }
1838	
1839	            // If head and tail are not in the same block, set `HAS_NEXT` in head.
1840	            if (head >> SHIFT) / LAP != (tail >> SHIFT) / LAP {
1841	                new_head |= HAS_NEXT;
1842	                // We can steal all tasks till the end of the block.
1843	                advance = (BLOCK_CAP - offset).min(limit);
1844	            } else {
1845	                let len = (tail - head) >> SHIFT;
1846	                // Steal half of the available tasks.
1847	                advance = len.div_ceil(2).min(limit);
1848	            }
1849	        } else {
1850	            // We can steal all tasks till the end of the block.
1851	            advance = (BLOCK_CAP - offset).min(limit);
1852	        }
1853	
1854	        new_head += advance << SHIFT;
1855	        let new_offset = offset + advance;
1856	
1857	        // Try moving the head index forward.
1858	        if self
1859	            .head
1860	            .index
1861	            .compare_exchange_weak(head, new_head, Ordering::SeqCst, Ordering::Acquire)
1862	            .is_err()
1863	        {
1864	            return Steal::Retry;
1865	        }
1866	
1867	        // Reserve capacity for the stolen batch.
1868	        let batch_size = new_offset - offset - 1;
1869	        dest.reserve(batch_size);
1870	
1871	        // Get the destination buffer and back index.
1872	        let dest_buffer = dest.buffer.get();
1873	        let dest_b = dest.inner.back.load(Ordering::Relaxed);
1874	
1875	        unsafe {
1876	            // If we've reached the end of the block, move to the next one.
1877	            if new_offset == BLOCK_CAP {
1878	                let next = (*block).wait_next();
1879	                let mut next_index = (new_head & !HAS_NEXT).wrapping_add(1 << SHIFT);
1880	                if !(*next).next.load(Ordering::Relaxed).is_null() {
1881	                    next_index |= HAS_NEXT;
1882	                }
1883	
1884	                self.head.block.store(next, Ordering::Release);
1885	                self.head.index.store(next_index, Ordering::Release);
1886	            }
1887	
1888	            // Read the task.
1889	            let slot = (*block).slots.get_unchecked(offset);
1890	            slot.wait_write();
1891	            let task = slot.task.get().read();
1892	
1893	            match dest.flavor {
1894	                Flavor::Fifo => {
1895	                    // Copy values from the injector into the destination queue.
1896	                    for i in 0..batch_size {
1897	                        // Read the task.
1898	                        let slot = (*block).slots.get_unchecked(offset + i + 1);
1899	                        slot.wait_write();
1900	                        let task = slot.task.get().read();
1901	
1902	                        // Write it into the destination queue.
1903	                        dest_buffer.write(dest_b.wrapping_add(i as isize), task);
1904	                    }
1905	                }
1906	
1907	                Flavor::Lifo => {
1908	                    // Copy values from the injector into the destination queue.
1909	                    for i in 0..batch_size {
1910	                        // Read the task.
1911	                        let slot = (*block).slots.get_unchecked(offset + i + 1);
1912	                        slot.wait_write();
1913	                        let task = slot.task.get().read();
1914	
1915	                        // Write it into the destination queue.
1916	                        dest_buffer.write(dest_b.wrapping_add((batch_size - 1 - i) as isize), task);
1917	                    }
1918	                }
1919	            }
1920	
1921	            // ThreadSanitizer does not understand fences, so we omit fence and do store with Release ordering.
1922	            #[cfg(not(crossbeam_sanitize_thread))]
1923	            atomic::fence(Ordering::Release);
1924	            let store_order = if cfg!(crossbeam_sanitize_thread) {
1925	                Ordering::Release
1926	            } else {
1927	                Ordering::Relaxed
1928	            };
1929	
1930	            // Update the back index in the destination queue.
1931	            dest.inner
1932	                .back
1933	                .store(dest_b.wrapping_add(batch_size as isize), store_order);
1934	
1935	            // Destroy the block if we've reached the end, or if another thread wanted to destroy
1936	            // but couldn't because we were busy reading from the slot.
1937	            if new_offset == BLOCK_CAP {
1938	                Block::destroy(block, offset);
1939	            } else {
1940	                for i in offset..new_offset {
1941	                    let slot = (*block).slots.get_unchecked(i);
1942	
1943	                    if slot.state.fetch_or(READ, Ordering::AcqRel) & DESTROY != 0 {
1944	                        Block::destroy(block, offset);
1945	                        break;
1946	                    }
1947	                }
1948	            }
1949	
1950	            Steal::Success(task.assume_init())
1951	        }
1952	    }
