2024	impl<T> Drop for Injector<T> {
2025	    fn drop(&mut self) {
2026	        let mut head = *self.head.index.get_mut();
2027	        let mut tail = *self.tail.index.get_mut();
2028	        let mut block = *self.head.block.get_mut();
2029	
2030	        // Erase the lower bits.
2031	        head &= !((1 << SHIFT) - 1);
2032	        tail &= !((1 << SHIFT) - 1);
2033	
2034	        unsafe {
2035	            // Drop all values between `head` and `tail` and deallocate the heap-allocated blocks.
2036	            while head != tail {
2037	                let offset = (head >> SHIFT) % LAP;
2038	
2039	                if offset < BLOCK_CAP {
2040	                    // Drop the task in the slot.
2041	                    let slot = (*block).slots.get_unchecked(offset);
2042	                    (*slot.task.get()).assume_init_drop();
2043	                } else {
2044	                    // Deallocate the block and move to the next one.
2045	                    let next = *(*block).next.get_mut();
2046	                    drop(Box::from_raw(block));
2047	                    block = next;
2048	                }
2049	
2050	                head = head.wrapping_add(1 << SHIFT);
2051	            }
2052	
2053	            // Deallocate the last remaining block.
2054	            drop(Box::from_raw(block));
2055	        }
2056	    }
2057	}
